mapper.select:
SELECT USER_EXP
FROM TBL_USER
WHERE ID = #{userId}

mapper.update:
UPDATE TBL_USER
SET USER_EXP = USER_EXP + #{amount}
WHERE ID = #{userId}

mapper.select:
SELECT COUNT(*)
FROM TBL_USER_EXP_HISTORY
WHERE USER_ID = #{userId}
  AND USER_EXP_HISTORY_TYPE = #{userExpHistoryType}
  AND USER_EXP_HISTORY_TARGET_ID = #{userExpHistoryTargetId}
